import React, { useEffect, useState, useRef } from 'react'
import styled from 'styled-components'
import {parseISO, differenceInMinutes} from 'date-fns'
import {Message} from './Message'
import {getAllMessages, sendMessage, getAllEmoji, fetchGiphyAPI} from '../WebAPI'
import emojiIcon from './static/emojiIcon.png'
import { Carousel } from '@giphy/react-components'
import { GiphyFetch } from '@giphy/js-fetch-api'


const ChatroomWrapper = styled.div `
margin:40px auto;
width:100%;
display:flex;
flex-direction:column;
border:1px solid rgb(220, 220, 220);

`

const ChatroomTitle = styled.div `
border-bottom:1px solid rgb(220, 220, 220);
display:flex;
align-items:center;
font-size:0.9rem;
padding:0 20px;
height:100px;
`

const ChatroomBody = styled.div `
height:500px;
padding:20px 10px;
box-sizing:border-box;
display:flex;
flex-direction:column;
overflow:scroll;
::-webkit-scrollbar {
    display: none;
}
`

const ItemImage = styled.div `
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
background-repeat:no-repeat;
background-position:center;
width:80px;
height:80px;
margin-right:20px;
border-radius:50%;
border:1px solid transparent;
`

const Left = styled.div `
width:30%;
display:flex;
align-items:center;
`

const ItemName = styled.div `
font-weight:800;
`

const ChatroomInputWrapper = styled.div `
height:50px;
text-align:center;
box-sizing:border-box;
position:relative;
display: flex;
align-items: center;

`

const ChatroomInput = styled.input `
border:1px solid rgb(220, 220, 220);
border-radius:20px;
color:grey;
padding:5px 15px;
font-size:0.9rem;
margin:0 auto;
width:95%;
height:30px;
`

const Time = styled.div `
color:#828282;
font-size:0.7rem;
margin:0 auto;
`

const EmojiIcon = styled.div `
background-image:url(${emojiIcon});
width:27px;
height:27px;
margin-left:94%;
background-size:cover;
background-repeat:no-repeat;
position:absolute;
&:hover {
	cursor:pointer;
}
`

const EmojiSection = styled.div `
height:150px;
background-color:white;
position:absolute;
width:1065px;
margin-top:450px;
box-sizing:border-box;
::-webkit-scrollbar {
    display: none;
}
`

const Emojis = styled.div `
height:110px;
overflow:scroll;
`

const SingleEmoji = styled.div `
width:20px;
height:20px;
margin:5px;
display:inline-block;
&:hover {
	cursor:pointer;
}
`

const EmojiSearch = styled.input `
background-color:rgb(240, 240, 240);
border-radius:20px;
border:0;
width:260px;
height:30px;
display:block;
margin-left:5px;
margin-top:10px;
margin-bottom:10px;
padding:0 10px;
box-sizing:border-box;
`

export default function Chatroom ({chatroomId, messages}) {
	const [userNow, setUserNow] = useState(null)
	const [messageData, setMessageData] = useState([{}])
	const [inputValue, setInputValue] = useState('')
	const [listOfEmoji, setListOfEmoji] = useState([])
	const [emojiSection, setEmojiSection] = useState(false)
	const [emojiSearchInput, setEmojiSearchInput] = useState('')
	const [gifSearchInput, setGifSearchInput] = useState('')
	const messageRef = useRef(null)
	const emojiRef = useRef(null)

	useEffect(() => {
		getAllMessages(chatroomId, setMessageData)
		getAllEmoji('c0af9a732c4e8366dca3d8b2682a7f14bc1856bc', setListOfEmoji, emojiRef)
		const user = localStorage.getItem('username')
		if (user) {
			setUserNow(user)
		}

		const messageMap = getMap(messageRef)
		const lastMessageNode = messageMap.get(messageData[messageData.length - 1].id)
		lastMessageNode.scrollIntoView({behavior: 'smooth'})

	},[messageData.length])

	let messageArr = []
	for (let message of messages) {
		if (message.Chatroom_id === chatroomId) {
			messageArr.push(message)
		}
	}
	const message = {...messageArr[0]}


	const onInput = e => {
		setInputValue(e.target.value)
	}

	const onKeyin = e => {
		if (e.key === 'Enter') {
			sendMessage(inputValue, setMessageData, messageData, Number(localStorage.getItem('userId')), chatroomId)
			setInputValue('')
		}
	}

	const getMap = (ref) => {
		if (!ref.current) {
			ref.current = new Map()
		}
		return ref.current
	}

	const getNode = (node, key, ref) => {
		const map = getMap(ref)
		if (node) {
			map.set(key, node)
		}
	}

	const onOpenEmojiSection = () => {
		setEmojiSection(!emojiSection)
	}


	const onSearchEmoji = e => {
		setEmojiSearchInput(e.target.value)
		setListOfEmoji(emojiRef.current.filter(emoji => emoji.unicodeName.indexOf(e.target.value) !== -1))
	}

	const gf = new GiphyFetch('RK8dL5SUArN7v9RBQLL8i6Ar7bMR7Pw6')
	const fetchGifs = (offset) => gf.trending({ offset, limit: 10 })

	const onSearchGIF = async e => {
		setGifSearchInput(e.target.value)
		const { data } = await gf.search(e.target.value, { sort: 'relevant', lang: 'es', limit: 10, type: 'stickers' })
		console.log(data)

	}

	const onSubmitEmoji = (emoji) => {
		console.log([...inputValue,emoji])
		setInputValue([...inputValue,emoji].join(''))
	}

	return (
		<ChatroomWrapper>
			<ChatroomTitle>
				<Left>
					<ItemImage image={message.image_1}/>
					<ItemName>{message.itemName}</ItemName>
				</Left>
			</ChatroomTitle>
			<ChatroomBody>
				{messageData.map((message, index) => 
				<>
					{index > 0 ? 
					(differenceInMinutes(parseISO(message.createdAt), parseISO(messageData[index - 1].createdAt)) > 10 ? 
					<Time>{parseISO(message.createdAt).toString().split(' GMT+0800 (Taipei Standard Time)')[0]}</Time> : null) : <Time>{parseISO(message.createdAt).toString().split(' GMT+0800 (Taipei Standard Time)')[0]}</Time>}
					<Message key={message.id} message={message} ref={node => getNode(node, message.id, messageRef)}/>
				</>
				)}
			</ChatroomBody>
			{emojiSection ? <EmojiSection>
				<EmojiSearch placeholder='SEARCH EMOJI' onChange={onSearchEmoji} value={emojiSearchInput}></EmojiSearch>
				<Emojis>
					{listOfEmoji.map(emoji => <SingleEmoji onClick={() => onSubmitEmoji(emoji.character)}>{emoji.character}</SingleEmoji>)}
				</Emojis>
			</EmojiSection> : null}
			<EmojiSearch placeholder='SEARCH GIFS' onChange={onSearchGIF} value={gifSearchInput}></EmojiSearch>
			<Carousel gifHeight={200} gutter={6} fetchGifs={fetchGifs}></Carousel>
			<ChatroomInputWrapper>
				<EmojiIcon onClick={onOpenEmojiSection}></EmojiIcon>
				<ChatroomInput type='text' onChange={onInput} value={inputValue} onKeyDown={onKeyin} placeholder='Message...'/>
			</ChatroomInputWrapper>
		</ChatroomWrapper>
	)
}
